+import { render, screen, fireEvent } from '@testing-library/react';
+import { createRef } from 'react';
+import { MiniProductCard } from './MiniProductCard';
+import type { MiniProductCardProps } from './MiniProductCard';
+
+const BASE_PROPS: MiniProductCardProps = {
+  name: 'Sport-Tek Competitor Lightweight Performance Polo',
+  linkHref: '/products/sport-tek-competitor-polo',
+  imageSrc:
+    'https://mms-images.out.customink.com/mms/images/catalog/e109d2348e5a6328e3c11430602c69f7/colors/577204/views/alt/front_medium_extended.png?autoNegate=1&ixbg=%23ffffff&ixfm=jpeg&ixq=60&ixw=270&placeMax=1&placeMaxPct=0.8&placeUseProduct=1&placeUseView=front',
+};
+
+describe('MiniProductCard', () => {
+  it('renders the product name', () => {
+    render(<MiniProductCard {...BASE_PROPS} />);
+    expect(screen.getByText(BASE_PROPS.name)).toBeInTheDocument();
+  });
+
+  it('renders a link to the product page', () => {
+    render(<MiniProductCard {...BASE_PROPS} />);
+    const link = screen.getByRole('link');
+    expect(link).toHaveAttribute('href', BASE_PROPS.linkHref);
+  });
+
+  it('renders the product image with correct src', () => {
+    render(<MiniProductCard {...BASE_PROPS} />);
+    expect(screen.getByAltText(BASE_PROPS.name)).toHaveAttribute('src', BASE_PROPS.imageSrc);
+  });
+
+  it('uses imageAlt when provided', () => {
+    render(<MiniProductCard {...BASE_PROPS} imageAlt="Custom alt" />);
+    expect(screen.getByAltText('Custom alt')).toBeInTheDocument();
+  });
+
+  it('defaults imageAlt to name', () => {
+    render(<MiniProductCard {...BASE_PROPS} />);
+    expect(screen.getByAltText(BASE_PROPS.name)).toBeInTheDocument();
+  });
+
+  it('passes imageSrcSet to the img element', () => {
+    render(<MiniProductCard {...BASE_PROPS} imageSrcSet="polo-2x.jpg 2x" />);
+    expect(screen.getByAltText(BASE_PROPS.name)).toHaveAttribute('srcset', 'polo-2x.jpg 2x');
+  });
+
+  it('calls onClick when the card is clicked', () => {
+    const onClick = jest.fn();
+    render(<MiniProductCard {...BASE_PROPS} onClick={onClick} />);
+    fireEvent.click(screen.getByRole('link'));
+    expect(onClick).toHaveBeenCalledTimes(1);
+  });
+
+  it('forwards ref to the root element', () => {
+    const ref = createRef<HTMLAnchorElement>();
+    render(<MiniProductCard {...BASE_PROPS} ref={ref} />);
+    expect(ref.current).toBeInstanceOf(HTMLAnchorElement);
+  });
+
+  it('applies custom className', () => {
+    const ref = createRef<HTMLAnchorElement>();
+    render(<MiniProductCard {...BASE_PROPS} className="custom" ref={ref} />);
+    expect(ref.current?.className).toContain('custom');
+  });
+
+  it('renders data-testid attributes', () => {
+    render(<MiniProductCard {...BASE_PROPS} />);
+    expect(screen.getByTestId('mini-product-card')).toBeInTheDocument();
+    expect(screen.getByTestId('mini-product-card-image')).toBeInTheDocument();
+    expect(screen.getByTestId('mini-product-card-name')).toBeInTheDocument();
+  });
+
+  it('sets title attribute on the name for tooltip on truncated text', () => {
+    render(<MiniProductCard {...BASE_PROPS} />);
+    expect(screen.getByTestId('mini-product-card-name')).toHaveAttribute('title', BASE_PROPS.name);
+  });
+});
